// Calculate Ranks v4.0: Weighted champion selection (60% recent 7d, 40% total)
const API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRuZGF2ZnZma2tsbXVkYnBmZGhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc4OTc5MjgsImV4cCI6MjA4MzQ3MzkyOH0.TbFIFNUnYACyAT8c_vl3agifPPx8ut0OcCoz6JJ2aBY';
const BASE_URL = 'https://tndavfvfkklmudbpfdhj.supabase.co/rest/v1';
const headers = { 'apikey': API_KEY, 'Authorization': 'Bearer ' + API_KEY };

const portfolioItems = $input.all();
const allPortfolios = portfolioItems.map(item => item.json).filter(p => p && p.id);

if (allPortfolios.length === 0) {
  return [{ json: { error: 'No portfolios' } }];
}

// 중복 제거
const uniquePortfolios = [];
const seen = new Set();
for (const p of allPortfolios) {
  if (p.id && !seen.has(p.id)) {
    seen.add(p.id);
    uniquePortfolios.push(p);
  }
}

// ========== v4.0: Fetch recent 7-day performance ==========
let recentByModel = {};
try {
  const sevenDaysAgo = new Date(Date.now() - 7*24*60*60*1000).toISOString();
  const recentPerf = await this.helpers.httpRequest({
    method: 'GET',
    url: BASE_URL + '/performance_history?recorded_at=gte.' + sevenDaysAgo + '&order=recorded_at.desc',
    headers: headers,
    json: true
  });

  // Group records by model_id
  for (const rec of (recentPerf || [])) {
    if (!recentByModel[rec.model_id]) {
      recentByModel[rec.model_id] = { records: [], startBalance: null, endBalance: null };
    }
    recentByModel[rec.model_id].records.push(rec);
  }

  // Calculate 7-day return for each model
  for (const modelId of Object.keys(recentByModel)) {
    const recs = recentByModel[modelId].records;
    if (recs.length >= 2) {
      const newest = parseFloat(recs[0].balance) || 10000;
      const oldest = parseFloat(recs[recs.length - 1].balance) || 10000;
      recentByModel[modelId].return7d = oldest > 0 ? ((newest - oldest) / oldest) * 100 : 0;
    } else {
      recentByModel[modelId].return7d = 0;
    }
  }
} catch (e) {
  // If fetch fails, continue with empty recent data
  recentByModel = {};
}
// ========== END v4.0 ==========

// ========== v4.0: Weighted score calculation ==========
const sorted = uniquePortfolios
  .map(p => {
    const recent = recentByModel[p.model_id] || {};
    const totalPnl = (parseFloat(p.current_balance) || 10000) - 10000;
    const return7d = recent.return7d || 0;

    // Weighted score: 60% recent 7-day return + 40% total PnL (normalized)
    const weightedScore = (return7d * 0.6) + ((totalPnl / 100) * 0.4);

    return {
      id: p.id,
      model_id: p.model_id,
      model_name: p.ai_models?.name || 'Unknown',
      current_balance: parseFloat(p.current_balance) || 10000,
      realized_pnl: parseFloat(p.realized_pnl) || 0,
      return7d: return7d,
      weightedScore: weightedScore
    };
  })
  .sort((a, b) => b.weightedScore - a.weightedScore);
// ========== END v4.0 ==========

// 랭킹 및 챔피언 설정 - 가중 점수 1등만 is_champion=true
return sorted.map((p, idx) => ({
  json: {
    portfolio_id: p.id,
    model_id: p.model_id,
    model_name: p.model_name,
    current_rank: idx + 1,
    is_champion: idx === 0,
    current_balance: p.current_balance,
    realized_pnl: p.realized_pnl,
    return7d: p.return7d,
    weightedScore: p.weightedScore
  }
}));

