// ============================================
// Sync TL First v2.1: Fixed SL/TP Detection
// Bug Fix: Check actual SL/TP levels instead of price comparison
// ============================================

const API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRuZGF2ZnZma2tsbXVkYnBmZGhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc4OTc5MjgsImV4cCI6MjA4MzQ3MzkyOH0.TbFIFNUnYACyAT8c_vl3agifPPx8ut0OcCoz6JJ2aBY';
const BASE_URL = 'https://tndavfvfkklmudbpfdhj.supabase.co/rest/v1';

try {
  // 1. TradeLocker 토큰 가져오기
  const configRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/system_config?key=eq.tradelocker_access_token`,
    headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}` },
    json: true
  });

  if (!configRes || configRes.length === 0) {
    return [{ json: { synced: false, reason: 'No TL token' } }];
  }

  let accessToken = configRes[0].value;
  try { accessToken = JSON.parse(accessToken); } catch(e) {}

  // 2. TradeLocker 계정 정보
  const accountRes = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://demo.tradelocker.com/backend-api/auth/jwt/all-accounts',
    headers: { 'Authorization': `Bearer ${accessToken}`, 'accNum': '0' },
    json: true
  });

  const account = accountRes.accounts?.[0];
  if (!account) {
    return [{ json: { synced: false, reason: 'No TL account' } }];
  }

  // 3. TradeLocker 포지션 조회
  const posRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://demo.tradelocker.com/backend-api/trade/accounts/${account.id}/positions`,
    headers: { 'Authorization': `Bearer ${accessToken}`, 'accNum': String(account.accNum) },
    json: true
  });

  const rawPositions = posRes.d?.positions || [];
  const btcTLPositions = rawPositions
    .map(p => Array.isArray(p) ? { id: String(p[0]), instrumentId: String(p[1]) } : p)
    .filter(p => String(p.tradableInstrumentId || p.instrumentId) === '9503');

  const realPositionIds = btcTLPositions.map(p => String(p.id));

  // 4. OPEN인데 TL에 없는 execution 조회
  const execRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/trade_executions?position_status=eq.OPEN`,
    headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}` },
    json: true
  });

  const staleExecutions = (execRes || []).filter(e => 
    e.position_status === 'OPEN' && 
    e.tradelocker_position_id &&
    !realPositionIds.includes(String(e.tradelocker_position_id))
  );

  if (staleExecutions.length === 0) {
    return [{ json: { synced: true, staleCount: 0, reason: 'No stale executions' } }];
  }

  // 5. 챔피언 포트폴리오 조회
  const champRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/virtual_portfolios?is_champion=eq.true&select=*,ai_models(name)`,
    headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}` },
    json: true
  });

  const champion = champRes?.[0];
  if (!champion) {
    return [{ json: { synced: false, reason: 'No champion' } }];
  }

  // 6. 챔피언의 OPEN 가상 포지션 조회
  const vPosRes = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/virtual_positions?status=eq.OPEN&model_id=eq.${champion.model_id}`,
    headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}` },
    json: true
  });

  // 현재 가격 조회
  const priceRes = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://fapi.binance.com/fapi/v1/ticker/price?symbol=BTCUSDT',
    json: true
  });
  const currentPrice = parseFloat(priceRes.price) || 0;

  // 7. 청산된 포지션 찾기 및 DB 업데이트
  let closedCount = 0;
  let totalPnl = 0;

  for (const vPos of (vPosRes || [])) {
    if (vPos.status !== 'OPEN') continue;

    const execSide = vPos.side === 'LONG' ? 'buy' : 'sell';
    const matchingStale = staleExecutions.find(e => 
      e.champion_model_id === champion.model_id &&
      e.side === execSide
    );

    if (matchingStale) {
      // TP/SL로 청산됨!
      const entryPrice = parseFloat(vPos.entry_price) || 0;
      const tp = parseFloat(vPos.take_profit) || 0;
      const sl = parseFloat(vPos.stop_loss) || 0;
      const qty = parseFloat(vPos.quantity) || 0;
      const leverage = parseFloat(vPos.leverage) || 5;

      // ========== BUG FIX v2.1 ==========
      // Check ACTUAL SL/TP levels instead of price comparison
      let closedPrice = currentPrice;
      let closedBy = 'AI_DECISION';  // Default: AI decided to close

      if (vPos.side === 'LONG') {
        if (tp && currentPrice >= tp) {
          closedPrice = tp;
          closedBy = 'TP';
        } else if (sl && currentPrice <= sl) {
          closedPrice = sl;
          closedBy = 'SL';
        }
      } else { // SHORT
        if (tp && currentPrice <= tp) {
          closedPrice = tp;
          closedBy = 'TP';
        } else if (sl && currentPrice >= sl) {
          closedPrice = sl;
          closedBy = 'SL';
        }
      }
      // ========== END BUG FIX ==========

      const grossPnl = vPos.side === 'LONG'
        ? (closedPrice - entryPrice) * qty * leverage
        : (entryPrice - closedPrice) * qty * leverage;
      const netPnl = grossPnl - 3.18;

      // virtual_positions 업데이트
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${BASE_URL}/virtual_positions?id=eq.${vPos.id}`,
        headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: { status: 'CLOSED', closed_at: new Date().toISOString(), close_price: closedPrice, realized_pnl: netPnl },
        json: true
      });

      // trade_executions 업데이트
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${BASE_URL}/trade_executions?id=eq.${matchingStale.id}`,
        headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: { position_status: 'CLOSED', error_message: `Closed by ${closedBy} at $${closedPrice.toFixed(1)}` },
        json: true
      });

      totalPnl += netPnl;
      closedCount++;
    }
  }

  // 8. 포트폴리오 잔고 업데이트
  if (closedCount > 0 && totalPnl !== 0) {
    const newBalance = parseFloat(champion.current_balance) + totalPnl;
    const newRealizedPnl = parseFloat(champion.realized_pnl || 0) + totalPnl;
    const newTrades = (champion.total_trades || 0) + closedCount;
    const newWins = (champion.winning_trades || 0) + (totalPnl > 0 ? closedCount : 0);

    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${BASE_URL}/virtual_portfolios?id=eq.${champion.id}`,
      headers: { 'apikey': API_KEY, 'Authorization': `Bearer ${API_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: { current_balance: Math.round(newBalance * 100) / 100, realized_pnl: Math.round(newRealizedPnl * 100) / 100, total_trades: newTrades, winning_trades: newWins, updated_at: new Date().toISOString() },
      json: true
    });
  }

  return [{ json: { synced: true, closedCount, totalPnl: Math.round(totalPnl * 100) / 100, championName: champion.ai_models?.name || 'Unknown' } }];

} catch (e) {
  return [{ json: { synced: false, error: e.message } }];
}
